+        let snapshot = DbStatSnapshot {
+            file_reservations: 2,
+            reservation_snapshots: Vec::new(),
+            ..DbStatSnapshot::default()
+        };
+        assert!(
+            reservation_state_requires_time_refresh(&snapshot, now_micros()),
+            "active reservation count without rows must force refresh"
+        );
+    }
